    AtomicLock lock(LBL_POLL);
    if (!m_idle) {
        m_idle = 1;
        on_demand_helper.remove(this);
    }
}

unsigned poll::OnDemand::count_ondemand() {
    AtomicLock lock(LBL_POLL);
    return ListCore::len(g_list_demand);
}

poll::Timekeeper::Timekeeper()
    : m_clock(&null_timer)
    , m_tref(null_timer.now())
{
